mapper.select:
SELECT id, title, description, completed, user_id, created_time FROM task WHERE user_id = #{userId}
AND completed = #{status}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_time DESC

